import{_ as t,o,c as a,a0 as i}from"./chunks/framework.Bogozrur.js";const h=JSON.parse('{"title":"감사 로그(Audit Event) 설계","description":"제로 트러스트의 첫걸음인 통신 모니터링을 위해 JSON Schema 기반 공통 규격으로 감사 로그를 정형화하고 모니터링에 연동한 설계를 설명합니다.","frontmatter":{"title":"감사 로그(Audit Event) 설계","description":"제로 트러스트의 첫걸음인 통신 모니터링을 위해 JSON Schema 기반 공통 규격으로 감사 로그를 정형화하고 모니터링에 연동한 설계를 설명합니다."},"headers":[],"relativePath":"posts/audit-event-design.md","filePath":"posts/audit-event-design.md"}'),d={name:"posts/audit-event-design.md"};function r(l,e,s,c,n,u){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="기록이-남아야-통제할-수-있다-감사-로그-audit-event-설계" tabindex="-1">기록이 남아야 통제할 수 있다: 감사 로그(Audit Event) 설계 <a class="header-anchor" href="#기록이-남아야-통제할-수-있다-감사-로그-audit-event-설계" aria-label="Permalink to &quot;기록이 남아야 통제할 수 있다: 감사 로그(Audit Event) 설계&quot;">​</a></h1><p>개발팀에서 AI 도구를 활발히 쓰기 시작하면, 보안 관리자나 플랫폼 엔지니어가 마주하는 답답함은 바로 **&quot;불투명성&quot;**입니다.</p><blockquote><p>&quot;대체 누가, 어떤 모델을 써서, 우리 코드베이스를 대상으로 어떤 프롬프트를 날렸는지 알 수가 없다.&quot;</p></blockquote><p>사용 여부조차 블랙박스인 상태에서는 아무리 좋은 정책 가이드라인을 배포해 봤자 공염불에 불과합니다. 제로 트러스트(Zero Trust) 철학의 출발점은 **&quot;모든 행동은 기록되고, 사후에 추적 가능해야 한다&quot;**는 것입니다.</p><p>GoVail은 이 불투명성을 걷어내기 위해 <strong>표준화된 감사 로그(Audit Event) 시스템</strong>을 설계에 내재화했습니다.</p><hr><h2 id="_1-로그-포맷은-명확하고-지루해야-한다-schema-first" tabindex="-1">1. 로그 포맷은 명확하고 지루해야 한다 (Schema-First) <a class="header-anchor" href="#_1-로그-포맷은-명확하고-지루해야-한다-schema-first" aria-label="Permalink to &quot;1. 로그 포맷은 명확하고 지루해야 한다 (Schema-First)&quot;">​</a></h2><p>수많은 마이크로서비스가 얽혀 있는 시스템에서 각자 자기만의 형식으로 로그를 남기기 시작하면 사후 분석이나 통합 대시보드(Grafana 등) 구성은 헬게이트가 열립니다.</p><p>GoVail은 처음부터 게이트웨이, 런타임, 대시보드 콘솔이 일치된 약속 하에 데이터를 주고받도록 <strong>JSON Schema</strong>를 먼저 설계했습니다. (이 스키마들은 <code>govail-contracts</code> 레포지토리에서 통합 관리됩니다.)</p><ul><li><strong>이유</strong>: 게이트웨이(Rust)와 분석기(Python), 런타임 간에 서로 다른 프로그래밍 언어를 쓰더라도 감사 이벤트의 데이터 포맷이 절대 어긋나지 않도록 강제하기 위함입니다.</li><li><strong>예시</strong>: <code>audit_event.schema.json</code>은 모든 AI 요청 발생 시 다음과 같은 항목을 의무적으로 담도록 선언합니다. <ul><li><code>event_id</code>: 고유 식별자 (UUID)</li><li><code>timestamp</code>: RFC3339 규격 시간</li><li><code>actor</code>: 요청을 보낸 개발자 또는 시스템 식별자</li><li><code>model_requested</code>: 요청한 모델명</li><li><code>status</code>: <code>allowed</code> (허용됨) / <code>blocked</code> (차단됨) / <code>flagged</code> (경고 검출됨)</li><li><code>violation_reason</code>: 차단 시 구체적 위반 규칙 종류 (예: <code>secret_detected</code>)</li></ul></li></ul><hr><h2 id="_2-감사-로그의-기록-시점" tabindex="-1">2. 감사 로그의 기록 시점 <a class="header-anchor" href="#_2-감사-로그의-기록-시점" aria-label="Permalink to &quot;2. 감사 로그의 기록 시점&quot;">​</a></h2><p>GoVail Gateway는 두 가지 시점에 감사 로그를 발행합니다.</p><ol><li><strong>차단 즉시 (Blocking Path)</strong>: <ul><li>만약 프롬프트 스캔 단계에서 <code>secret_detected</code> 룰에 걸려 요청이 파기되는 경우, Gateway는 LLM 상위 노드로 네트워크 요청을 보내기 직전에 차단 사실을 감사 로그로 즉시 떨어뜨리고 클라이언트에게 에러 코드를 내려줍니다.</li></ul></li><li><strong>정상 트래픽 처리 완료 시 (Forwarding Path)</strong>: <ul><li>필터를 무사히 통과해 LLM으로부터 정상 답변을 수신하면, 트래픽 메트릭(사용된 토큰 수, 소요 시간 등)을 첨부한 이벤트 로그가 남습니다.</li></ul></li></ol><p>이렇게 축적된 감사 로그는 단순히 디스크에 파일로 쌓일 수도 있고, Temporal 워크플로우를 거쳐 저장소에 적재되거나 Prometheus/Grafana 대시보드로 전달되어 실시간 모니터링 그래프를 그리는 밑바탕이 됩니다.</p><hr><h2 id="_3-개인정보-유출-pii-과-감사-로그의-딜레마" tabindex="-1">3. 개인정보 유출(PII)과 감사 로그의 딜레마 <a class="header-anchor" href="#_3-개인정보-유출-pii-과-감사-로그의-딜레마" aria-label="Permalink to &quot;3. 개인정보 유출(PII)과 감사 로그의 딜레마&quot;">​</a></h2><p>감사 로그 자체가 또 다른 개인정보나 기밀 유출의 온상이 되지 않도록 설계에 특별한 주의를 기울여야 합니다. GoVail은 감사 로그 기록 시 <strong>사용자의 원본 프롬프트 내용 전체를 무조건 저장하지 않는 옵션</strong>을 기본 탑재할 계획입니다. 대신 위험 패턴 감지 여부, 위반 단어의 마스킹된 조각(예: <code>sk-proj-****</code>)만을 기록하도록 유도하여 감사 로그 자체의 보안 무결성을 지킵니다.</p>',18)])])}const _=t(d,[["render",r]]);export{h as __pageData,_ as default};
